export const RELAY_SCHEMA_VERSION = 1;
export const RELAY_TODO_STATUS = "todo";
export const RELAY_IN_PROGRESS_STATUS = "in_progress";
export const RELAY_NEEDS_CLARIFICATION_STATUS = "needs_clarification";
export const RELAY_REVIEW_STATUS = "review";
export const RELAY_NOT_DOING_STATUS = "not_doing";
export const RELAY_COMPLETED_STATUS = "completed";

export const DEFAULT_COLUMNS: RelayColumn[] = [
  { id: RELAY_TODO_STATUS, name: "Todo", position: 1000, terminal: false },
  { id: RELAY_IN_PROGRESS_STATUS, name: "In Progress", position: 2000, terminal: false },
  { id: RELAY_NEEDS_CLARIFICATION_STATUS, name: "Needs Clarification", position: 3000, terminal: false },
  { id: RELAY_REVIEW_STATUS, name: "Review", position: 4000, terminal: false },
  { id: RELAY_NOT_DOING_STATUS, name: "Not Doing", position: 5000, terminal: true },
  { id: RELAY_COMPLETED_STATUS, name: "Completed", position: 6000, terminal: true }
];

export type TicketPriority = "low" | "medium" | "high" | "urgent";
export type TicketType = "task" | "epic";
export type RunStatus =
  | "idle"
  | "drafting"
  | "draft_failed"
  | "draft_complete"
  | "running"
  | "blocked"
  | "failed"
  | "completed"
  | "cancelled";
export type ProjectHealth = "ok" | "warning" | "error";
export type ThemePreference = "system" | "light" | "dark";
export type RelayActor = "user" | "codex" | "system";
export type RelayEventSource =
  | "manual_board"
  | "manual_ticket_edit"
  | "draft_generation"
  | "agent_execution"
  | "clarification_ui"
  | "system_reconciliation";

export type RelayColumn = {
  id: string;
  name: string;
  position: number;
  terminal: boolean;
};

export type ProjectSettings = {
  defaultModel: string | null;
  defaultApprovalPolicy: "untrusted" | "on-request" | "never";
  defaultSandboxMode: "read-only" | "workspace-write" | "danger-full-access";
  allowNonGitCodexRuns: boolean;
  ticketDraftingEnabled: boolean;
  codexExecutionEnabled: boolean;
};

export type ProjectConfig = {
  schemaVersion: number;
  projectId: string;
  name: string;
  createdAt: string;
  updatedAt: string;
  columns: RelayColumn[];
  settings: ProjectSettings;
};

export type ProjectSummary = {
  projectId: string | null;
  name: string;
  path: string;
  exists: boolean;
  isGitRepository: boolean;
  relayInitialized: boolean;
  health: ProjectHealth;
  healthMessages: string[];
  activeRunCount: number;
  swimlanes: ProjectSwimlaneSummary[];
  lastOpenedAt?: string;
};

export type ProjectSwimlaneSummary = {
  id: string;
  name: string;
  position: number;
  ticketCount: number;
  activeRunCount: number;
};

export type GitMetadataState = "loading" | "ready" | "not_git" | "unavailable" | "missing" | "error";

export type GitMetadata = {
  state: GitMetadataState;
  isGitRepository: boolean;
  branchName: string | null;
  isDetachedHead: boolean;
  commitSha: string | null;
  isDirty: boolean;
  changedFileCount: number | null;
  message: string | null;
  error: string | null;
  updatedAt: string;
};

export type GitMetadataOptions = {
  force?: boolean;
};

export type TicketFrontMatter = {
  schemaVersion: number;
  id: string;
  title: string;
  ticketType: TicketType;
  status: string;
  position: number;
  priority: TicketPriority;
  labels: string[];
  parentEpicId: string | null;
  subticketIds: string[];
  blockedByIds: string[];
  createdAt: string;
  updatedAt: string;
  codexThreadId: string | null;
  runStatus: RunStatus;
  lastRunId: string | null;
};

export type TicketRecord = {
  frontMatter: TicketFrontMatter;
  markdown: string;
  filePath: string;
};

export type TicketSummary = TicketFrontMatter & {
  excerpt: string;
  filePath: string;
};

export type TicketReferenceCandidate = {
  id: string;
  title: string;
  status: string;
  columnName: string;
  relativePath: string;
  linkPath: string;
};

export type InvalidTicket = {
  filePath: string;
  reason: string;
};

export type BoardSnapshot = {
  project: ProjectSummary;
  config: ProjectConfig | null;
  columns: RelayColumn[];
  tickets: TicketSummary[];
  invalidTickets: InvalidTicket[];
};

export type TicketDraftSubticket = {
  title: string;
  priority: TicketPriority;
  labels: string[];
  context: string;
  researchFindings: string[];
  requirements: string[];
  implementationPlan: string[];
  testPlan?: string[];
  acceptanceCriteria: string[];
  clarificationQuestions: string[];
  assumptions?: string[];
  implementationNotes: string[];
};

export type TicketDraft = TicketDraftSubticket & {
  draftState?: "ready" | "needs_clarification";
  blockingClarificationQuestions?: string[];
  ticketType: TicketType;
  subtickets: TicketDraftSubticket[];
  research: TicketDraftResearch;
};

export type TaskPlanDraft = TicketDraftSubticket;
export type EpicPlanDraft = TicketDraft & { ticketType: "epic" };

export type TicketDraftResearchUrl = {
  url: string;
  status: "fetched" | "failed" | "skipped";
  title: string | null;
  reason: string | null;
  charactersRead: number;
};

export type TicketDraftResearchFile = {
  path: string;
  reason: string;
  symbols: string[];
  matches: string[];
  charactersRead: number;
};

export type TicketDraftResearchLimits = {
  maxResearchMs: number;
  maxUrls: number;
  maxUrlFetchMs: number;
  maxUrlContentChars: number;
  maxFilesToScan: number;
  maxFilesToRead: number;
  maxFileReadChars: number;
  maxMatchesPerFile: number;
};

export type TicketDraftResearch = {
  generatedAt: string;
  checkedUrls: TicketDraftResearchUrl[];
  inspectedFiles: TicketDraftResearchFile[];
  limitations: string[];
  limits: TicketDraftResearchLimits;
};

import { Effect, Option, Schema, SchemaGetter } from "effect";
import * as SchemaIssue from "effect/SchemaIssue";
import * as SchemaParser from "effect/SchemaParser";
import type {
  AgentTicketUpdate,
  AgentTicketUpdateInput,
  AppRegistry,
  ClarificationAnswerInput,
  ClarificationQuestion,
  ClarificationQuestionStore,
  CreateDraftInput,
  EpicSubticketCreateInput,
  EpicSubticketLinkInput,
  GitMetadataOptions,
  ProjectConfig,
  ProjectSettings,
  RelayActor,
  RelayApprovalDecision,
  RelayCodexEvent,
  RelayColumn,
  RelayEventSource,
  RunLogLine,
  RunStatus,
  StartRunInput,
  SubticketCreateInput,
  TicketCreateInput,
  TicketDraft,
  TicketDraftResearch,
  TicketDraftResearchFile,
  TicketDraftResearchLimits,
  TicketDraftResearchUrl,
